SELECT user_access.user_name, readers.reader_name, readers.location
FROM user_access
JOIN readers ON user_access.reader_id = readers.reader_id;

SELECT COUNT(*)
FROM readers
WHERE firmware_version = '1.0.0';

SELECT reader_id, COUNT(DISTINCT event_id) AS unique_event_count
FROM event_logs
GROUP BY reader_id;

SELECT reader_name, REPLACE(hardware_version, ' ', '') AS hardware_version_clean
FROM readers
ORDER BY reader_name ASC;

SELECT user_id, MAX(activity_timestamp) AS last_activity
FROM user_audit
GROUP BY user_id;

SELECT * 
  FROM firmware_updates 
 WHERE reader_id = 1;
